import json
import subprocess
import os
from google.cloud import storage
from urllib.parse import unquote_plus

def image_converter(event, context):
    """Cloud Function triggered by Cloud Storage to convert images using ImageMagick."""
    
    # Validate event data
    if 'bucket' not in event or 'name' not in event:
        raise ValueError("Invalid event data")
    
    bucket_name = event['bucket']
    object_name = event['name']
    
    # Decode object name
    object_name = unquote_plus(object_name)
    
    # Validate object name to prevent path traversal
    if '..' in object_name or object_name.startswith('/'):
        raise ValueError("Invalid object name")
    
    # Get conversion options from metadata
    conversion_options = event.get('metadata', {}).get('conversion_options', '')
    
    # Validate conversion options (allowlist approach)
    allowed_options = [
        '-resize', '-quality', '-strip', '-gravity', '-crop',
        '-background', '-extent', '-rotate', '-flip', '-flop'
    ]
    
    if conversion_options:
        options_list = conversion_options.split()
        for opt in options_list:
            if opt not in allowed_options and not opt.startswith('-'):
                raise ValueError("Invalid conversion option")
    
    # Get filename without extension
    filename = os.path.splitext(object_name)[0]
    
    # Validate filename
    if not filename or filename.startswith('.'):
        raise ValueError("Invalid filename")
    
    # Secure processing
    try:
        # Download file from Cloud Storage
        storage_client = storage.Client()
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(object_name)
        
        # Create temporary file path
        temp_input = f"/tmp/{os.path.basename(object_name)}"
        temp_output = f"/tmp/{filename}_converted.jpg"
        
        # Download blob to temporary file
        blob.download_to_filename(temp_input)
        
        # Build convert command with validation
        cmd = ['convert', temp_input]
        
        if conversion_options:
            cmd.extend(conversion_options.split())
        
        cmd.extend([temp_output])
        
        # Execute convert command
        result = subprocess.call(cmd)
        
        if result != 0:
            raise RuntimeError("Image conversion failed")
        
        # Upload converted image back to Cloud Storage
        converted_blob = bucket.blob(f"{filename}_converted.jpg")
        converted_blob.upload_from_filename(temp_output)
        
        # Clean up temporary files
        os.remove(temp_input)
        os.remove(temp_output)
        
    except Exception as e:
        # Log error securely (avoid logging sensitive data)
        print(f"Error processing image: {str(e)}")
        raise